import{_ as e,c as a,a1 as i,o as r}from"./chunks/framework.CWcXGLD-.js";const d="/hinata-docs-vitepress/assets/spicecardio.BKGW6AkO.png",s="/hinata-docs-vitepress/assets/spicelight.BzFap2Cq.png",l="/hinata-docs-vitepress/assets/spicebrightness.zTKXxBI1.png",x=JSON.parse('{"title":"KONAMI 游戏配置说明","description":"","frontmatter":{},"headers":[],"relativePath":"KONAMI/index.md","filePath":"KONAMI/index.md"}'),n={name:"KONAMI/index.md"};function o(c,t,p,h,g,m){return r(),a("div",null,t[0]||(t[0]=[i('<h1 id="konami-游戏配置说明" tabindex="-1">KONAMI 游戏配置说明 <a class="header-anchor" href="#konami-游戏配置说明" aria-label="Permalink to &quot;KONAMI 游戏配置说明&quot;">​</a></h1><p><strong>该功能仅限标准版</strong></p><h2 id="cardio-读卡设置" tabindex="-1">CardIO 读卡设置 <a class="header-anchor" href="#cardio-读卡设置" aria-label="Permalink to &quot;CardIO 读卡设置&quot;">​</a></h2><ol><li><p>部分较旧的固件版本需要绑定 HID 灯光才能进行读卡</p></li><li><p>打开 <em>spicecfg</em> ，在顶部选择 <strong>Advanced</strong> ，找到 <code>CardIO HID Reader Support (-cardio)</code> 并勾选<br>如图所示：</p><p><img src="'+d+'" alt="spicecardio"></p></li><li><p>如果勾选 <code>CardIO HID Reader Support (-cardio)</code> 后读卡器不工作（可能会出现在远古版本的 Spice 或非 Windows10 及以上的版本上）请尝试勾选 <code>HID SmartCard</code></p></li><li><p>如果发现刷卡的槽位不对（例如 IIDX 这种有 1P 和 2P 的游戏）<br>请勾选下面的 <code>xxx Order Flip</code></p></li></ol><p>默认情况下 CardIO 偏向最高兼容性，能刷入的卡包括:</p><table tabindex="0"><thead><tr><th style="text-align:center;">卡类型</th><th style="text-align:center;">能否刷卡</th></tr></thead><tbody><tr><td style="text-align:center;">Amusement IC (四社通)</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:center;">任何 ISO14443-A</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:center;">任何 Felica 卡(Suica, AIC, Osaifu-Keitai)</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:center;">任何 Aime 卡</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:center;">ISO15693 (旧版 epass)</td><td style="text-align:center;">❌</td></tr></tbody></table><p>可以在 <a href="./../HCP/">HINATA 控制中心</a> 中控制可以读取的卡范围 （ISO14443A，Aime）</p><h2 id="hid-灯光绑定" tabindex="-1">HID 灯光绑定 <a class="header-anchor" href="#hid-灯光绑定" aria-label="Permalink to &quot;HID 灯光绑定&quot;">​</a></h2><p>当 SDVX 处于女武神框体模式时，IIDX 处于雷霆框体模式时，游戏就会向读卡器输出灯光。以下是绑定方式：</p><ol><li><p>打开 <em>spicecfg</em> ，在顶部选择 <strong>Lights</strong>，找到 <code>IC Card Reader *</code></p></li><li><p>按下图方式绑定:</p><p><img src="'+s+'" alt="spicelight"></p></li><li><p>IIDX 之类的有 2P 位的游戏会分为 1P、2P 共六个通道，绑定你有玩的 P 位，或者使用两个读卡器的时候可以都绑定</p></li><li><p>调整灯光亮度：在 <em>spicecfg</em> &gt; <strong>Advanced</strong> &gt; <code>Light Brightness Adjustment</code>内可以调整 <img src="'+l+'" alt="spicebrightness"></p></li></ol><h2 id="其他页面" tabindex="-1">其他页面 <a class="header-anchor" href="#其他页面" aria-label="Permalink to &quot;其他页面&quot;">​</a></h2><ul><li><a href="./../HCP/#cardio设置">调整 CardIO 读卡限制</a></li><li><a href="./../SEGA/">SEGA 游戏设置</a></li></ul>',12)]))}const u=e(n,[["render",o]]);export{x as __pageData,u as default};
